  ('judicial-a9db9bda-moex-00114', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '甲為某視聽著作之著作人，於創作完成後第5年始將該視聽著作對外公開發表，有關著作財產權的存續期 間，下列敘述何者正確？', '["若甲為法人，其著作財產權存續至創作完成時起50年", "若甲為法人，其著作財產權存續至該法人成立時起50年", "若甲為自然人，其著作財產權存續於甲的生存期間及其死亡後50年", "若甲為自然人，其著作財產權存續至該著作公開發表後50年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00115', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '保險醫事服務機構當年領取之保險醫療費用超過一定數額者，應於期限內向保險人提報經會計師簽證或審 計機關審定之全民健康保險業務有關之財務報告，下列何者非財務報告應包括之報表？', '["資產負債表", "現金流量表", "損益表", "淨值變動表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00116', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '當事人得以要約與承諾之方式成立契約。關於要約，下列敘述何者錯誤？', '["貨物標定賣價陳列者，依民法規定推定為要約", "契約之要約人，因要約而受拘束", "對話為要約者，除要約人另有意思表示外，非立時承諾，即失其拘束力", "要約定有承諾期限者，非於其期限內為承諾，失其拘束力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00117', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '依民法之規定，總會決議之內容違反法令或章程，其效力為何？', '["無效", "無效，但不得以其無效對抗善意之第三人", "須經主管機關、檢察官或利害關係人向法院聲請，以宣告其行為為無效", "社員得於決議後3個月內請求法院撤銷其決議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00118', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '甲將自己的A車以60萬元賣給乙，雙方約定下個月初交車及付款。不料，於交車前數日，A車於公共停 車場中遭雷電擊中而燒毀。依民法規定，下列敘述何者錯誤？', '["甲對乙免給付義務", "乙對甲免支付價金", "甲應對乙負債務不履行的損害賠償責任", "乙不得向甲請求給付A車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00119', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '甲任職於市政府警察局某分局派出所所長，因處理群眾陳抗事件，派出所人手不足，甲發現派出所內約聘 擔任庶務工作的事務工友乙因喜愛健身而身強體壯，遂拿一套警察制服給乙穿著，並命令乙與其他警員一 同至陳抗現場維持秩序。下列敘述何者正確？', '["乙進行群眾驅離，係依法令之行為，阻卻違法", "乙行使警察職權，係依所屬上級公務員之命令，阻卻違法", "乙依刑法第10條第2項規定，為公務員", "乙犯刑法第158條、第159條之冒充公務員行使職權罪與冒用公務員服章官銜罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00120', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-111-3d2b73b6', 'sub-judicial-a9db9bda-08', NULL, 'single_choice', '性別工作平等法中有關「性騷擾」之規定，下列敘述何者錯誤？', '["求職者於求職時，雇主以具有性意味之言詞或行為，對其造成冒犯，致侵犯其人格尊嚴，該當性別工作 平等法所定義之性騷擾", "求職者於求職時，雇主對求職者為明示之性要求，作為勞務契約成立之交換條件，該當性別工作平等法 所定義之性騷擾", "受僱者於執行職務時，客戶以具有性別歧視之言詞或行為，對其造成敵意性之工作環境，致影響其工作 表現，該當性別工作平等法所定義之性騷擾", "受僱者於執行職務時，其同事以具有性意味之言詞或行為，對其造成冒犯性之工作環境，致侵犯其人格 尊嚴，該當性別工作平等法所定義之性騷擾"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:43+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "113", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
